import React, { useState, useEffect } from 'react';
import axios from 'axios';

function AdminDashboard() {
  const [requests, setRequests] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => { fetchRequests(); }, []);

  const fetchRequests = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/requests');
      setRequests(res.data);
      setLoading(false);
    } catch (err) { console.error(err); setLoading(false); }
  };

  const handleUpdate = async (id, updatedData) => {
    try {
      await axios.put(`http://localhost:5000/api/update-status/${id}`, updatedData);
      fetchRequests(); // Refresh UI instantly
    } catch (err) { alert("Error updating!"); }
  };

  const markAsFullPaid = async (id, total) => {
    if (window.confirm("Mark as fully paid?")) {
      handleUpdate(id, { advancePaid: total, paymentStatus: 'Paid' });
    }
  };

  if (loading) return <div className="text-center py-5">Loading...</div>;

  return (
    <div className="container py-5">
      <h2 className="fw-bold mb-1">Admin <span className="text-primary">Control Panel</span></h2>
      <p className="text-muted mb-5">Manage your clients, project progress, and payments efficiently.</p>

      <div className="row g-4">
        {requests.map((project) => {
          const remaining = project.totalBudget - project.advancePaid;

          return (
            <div key={project._id} className="col-12">
              <div className="card shadow-sm border-0 rounded-4 p-4">
                <div className="row align-items-center">
                  
                  {/* Client Info */}
                  <div className="col-md-3">
                    <h5 className="fw-bold mb-0 text-capitalize">{project.fullName}</h5>
                    <small className="text-primary fw-bold d-block mb-1">{project.serviceType}</small>
                    <small className="text-muted">{project.email}</small>
                  </div>

                  {/* Progress Section (Cleaner UI) */}
                  <div className="col-md-3 px-4">
                    <div className="d-flex justify-content-between mb-2">
                      <span className="small fw-bold text-muted">Progress</span>
                      <span className="small fw-bold text-primary">{project.progress}%</span>
                    </div>
                    <div className="progress rounded-pill mb-3" style={{ height: '10px' }}>
                      <div className="progress-bar bg-primary" style={{ width: `${project.progress}%` }}></div>
                    </div>
                    {/* Control Slider */}
                    <input 
                      type="range" className="form-range custom-slider" min="0" max="100" 
                      value={project.progress} 
                      onChange={(e) => handleUpdate(project._id, { progress: e.target.value })}
                    />
                  </div>

                  {/* Payment Section (Calculated) */}
                  <div className="col-md-3 text-center border-start border-end">
                    <small className="text-muted d-block">Remaining Balance</small>
                    <h4 className={`fw-bold mb-0 ${remaining > 0 ? 'text-danger' : 'text-success'}`}>
                      ₹{remaining}
                    </h4>
                    <small className="text-muted">Total: ₹{project.totalBudget}</small>
                  </div>

                  {/* Actions */}
                  <div className="col-md-3 text-end">
                    {remaining > 0 ? (
                      <button className="btn btn-outline-success btn-sm px-4 rounded-pill fw-bold" onClick={() => markAsFullPaid(project._id, project.totalBudget)}>
                        Mark Full Paid
                      </button>
                    ) : (
                      <span className="badge bg-success-light text-success p-2 px-3 rounded-pill fw-bold">✅ Paid</span>
                    )}
                    <button className="btn btn-link text-danger ms-2" onClick={() => {if(window.confirm("Delete?")) axios.delete(`http://localhost:5000/api/delete-request/${project._id}`).then(fetchRequests)}}>
                      <i className="fas fa-trash"></i>
                    </button>
                  </div>

                </div>
              </div>
            </div>
          );
        })}
      </div>

      <style>{`
        .custom-slider { height: 5px; }
        .bg-success-light { background-color: #e8f5e9; }
      `}</style>
    </div>
  );
}

export default AdminDashboard;
